patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..64cf24d13c7a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1583,6 +1583,18 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   if (Instruction *Overflow = foldLShrOverflowBit(I))
     return Overflow;

+  // lshr (add (and X, 1), (and Y, 1)), 1 --> and (and X, 1), Y
+  // This is computing the carry bit of adding two 1-bit values.
+  Value *A, *B;
+  Instruction *AndA, *AndB;
+  if (match(Op1, m_One()) &&
+      match(Op0, m_c_Add(m_OneUse(m_Instruction(AndA)),
+                         m_OneUse(m_Instruction(AndB))))) {
+    if (match(AndA, m_And(m_Value(A), m_One())) &&
+        match(AndB, m_And(m_Value(B), m_One())))
+      return BinaryOperator::CreateAnd(AndB, A);
+  }
+
   return nullptr;
 }

